    .scroll-to-top:hover {
      transform: scale(1.1);
      background: #15803d;
    }
    
    .blue-list {
      border: 1px solid rgba(59,130,246,0.6);
      box-shadow: 0 0 40px rgba(59,130,246,0.3);
    }
    
    .blue-header {
      background: linear-gradient(135deg, rgba(59,130,246,0.2), rgba(59,130,246,0.05));
      border-bottom: 1px solid rgba(59,130,246,0.4);
    }
    
    .order-count-badge-blue {
      background: #3b82f6;
      color: white;
      border-radius: 25px;
      padding: 4px 12px;
      font-size: 0.8rem;
      font-weight: bold;
    }
    
    .order-item-blue {
      border-left-color: #3b82f6;
    }
    
    .order-price-blue {
      color: #60a5fa;
    }
    
    .order-quantity-badge-blue {
      background: rgba(59,130,246,0.25);
      color: #60a5fa;
    }
    
    .order-table-badge-blue {
      background: rgba(59,130,246,0.2);
      color: #60a5fa;
    }
    
    .refresh-btn-blue {
      background: rgba(255,255,255,0.15);
    }
    
    .refresh-btn-blue:hover {
      background: rgba(59,130,246,0.4);
    }
    
    .scroll-to-top-blue {
      background: linear-gradient(135deg, #3b82f6, #1d4ed8);
      box-shadow: 0 3px 15px rgba(59,130,246,0.5);
    }
    
    .scroll-to-top-blue:hover {
      background: linear-gradient(135deg, #60a5fa, #3b82f6);
    }
    
    .orange-list {
      border: 1px solid rgba(245,158,11,0.6);
      box-shadow: 0 0 40px rgba(245,158,11,0.3);
    }
    
    .orange-header {
      background: linear-gradient(135deg, rgba(245,158,11,0.2), rgba(245,158,11,0.05));
      border-bottom: 1px solid rgba(245,158,11,0.4);
    }
    
    .order-count-badge-orange {
      background: #f59e0b;
      color: white;
      border-radius: 25px;
      padding: 4px 12px;
      font-size: 0.8rem;
      font-weight: bold;
    }
    
    .order-item-orange {
      border-left-color: #f59e0b;
    }
    
    .order-price-orange {
      color: #fbbf24;
    }
    
    .order-table-badge-orange {
      background: rgba(245,158,11,0.2);
      color: #fbbf24;
    }
    
    .scroll-to-top-orange {
      background: linear-gradient(135deg, #f59e0b, #d97706);
      box-shadow: 0 3px 15px rgba(245,158,11,0.5);
    }
    
    .scroll-to-top-orange:hover {
      background: linear-gradient(135deg, #fbbf24, #f59e0b);
    }
    
    .btn-return-small {
      background: linear-gradient(135deg, #8b5cf6, #7c3aed);
      border: none;
      border-radius: 20px;
      padding: 5px 10px;
      color: white;
      font-size: 11px;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-return-small:hover {
      transform: scale(1.05);
    }
    
    .modal-overlay {
      position: fixed !important;
      top: 0 !important;
      left: 0 !important;
      right: 0 !important;
      bottom: 0 !important;
      background: rgba(0, 0, 0, 0.9) !important;
      backdrop-filter: blur(12px) !important;
      z-index: 10000 !important;
      display: flex !important;
      align-items: center !important;
      justify-content: center !important;
      animation: fadeIn 0.3s ease !important;
    }
    
    .modal-content-order {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      border: 2px solid #22c55e;
      box-shadow: 0 0 40px rgba(34, 197, 94, 0.3);
      animation: slideUp 0.4s ease;
      position: relative !important;
      z-index: 10001 !important;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 550px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
      box-shadow: 0 0 40px rgba(34, 197, 94, 0.3);
      animation: slideUp 0.4s ease;
      position: relative !important;
      z-index: 10001 !important;
    }
    
    .close-btn {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 24px;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .close-btn:hover {
      transform: scale(1.1);
      color: #ef4444;
    }
    
    .order-detail-info {
      text-align: left;
      margin: 20px 0;
      background: rgba(255, 255, 255, 0.05);
      padding: 15px;
      border-radius: 15px;
    }
    
    .order-detail-info p {
      margin: 8px 0;
      color: rgba(255, 255, 255, 0.8);
    }
    
    .detail-label {
      font-weight: bold;
      color: #22c55e;
      display: inline-block;
      width: 110px;
    }
    
    .order-detail-buttons {
      display: flex;
      gap: 15px;
      justify-content: center;
      margin-top: 20px;
      flex-wrap: wrap;
    }
    
    .btn-livre {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-annule {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-livre:hover, .btn-annule:hover {
      transform: scale(1.02);
      filter: brightness(1.1);
    }
    
    .status-badge-detail {
      display: inline-block;
      padding: 2px 10px;
      border-radius: 15px;
      font-size: 0.75rem;
      margin-left: 8px;
    }
    
    .status-badge-detail.pending {
      background: #f59e0b;
      color: white;
    }
    
    .status-badge-detail.completed {
      background: #22c55e;
      color: white;
    }
    
    .status-badge-detail.cancelled {
      background: #ef4444;
      color: white;
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-primary:hover {
      transform: scale(1.02);
      filter: brightness(1.1);
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    .animate-slide-up {
      animation: slideUp 0.3s ease-out forwards;
    }
    
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(5px);
    }
    
    .cards-container {
      display: flex;
      gap: 20px;
      justify-content: center;
      margin-top: 40px;
      flex-wrap: wrap;
      position: relative;
      padding-bottom: 30px;
      z-index: 1;
      transition: transform 0.3s ease-in-out;
    }
    
    .cards-container::after {
      content: '';
      position: absolute;
      bottom: -15px;
      left: 10%;
      width: 80%;
      height: 4px;
      background: linear-gradient(90deg, transparent, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000, transparent);
      background-size: 200% 100%;
      border-radius: 4px;
      animation: rainbowLine 3s linear infinite;
      box-shadow: 0 0 15px rgba(255,0,0,0.5), 0 0 8px rgba(0,255,255,0.3);
    }
    
    .cv-card {
      flex: 1;
      min-width: 260px;
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 35px 25px;
      cursor: pointer;
      transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      text-align: center;
      position: relative;
      overflow: hidden;
      z-index: 5;
      animation: float 4s ease-in-out infinite;
    }
    
    @keyframes float {
      0%, 100% { transform: translateY(0px) translateX(0px); }
      25% { transform: translateY(-8px) translateX(4px); }
      75% { transform: translateY(8px) translateX(-4px); }
    }
    
    .cv-card:nth-child(1) {
      background: linear-gradient(135deg, #FF6B6B 0%, #FF8E53 50%, #FF6B6B 100%);
      background-size: 200% 200%;
      box-shadow: 0 15px 35px rgba(255, 107, 107, 0.3);
      border: 1px solid rgba(255, 255, 255, 0.4);
      animation-delay: 0s;
    }
    
    .cv-card:nth-child(1):hover {
      background-position: 100% 100%;
      transform: translateY(-12px) scale(1.02);
      box-shadow: 0 25px 45px rgba(255, 107, 107, 0.5);
    }
    
    .cv-card:nth-child(2) {
      background: linear-gradient(135deg, #4ECDC4 0%, #556270 50%, #4ECDC4 100%);
      background-size: 200% 200%;
      box-shadow: 0 15px 35px rgba(78, 205, 196, 0.3);
      border: 1px solid rgba(255, 255, 255, 0.4);
      animation-delay: 0.5s;
    }
    
    .cv-card:nth-child(2):hover {
      background-position: 100% 100%;
      transform: translateY(-12px) scale(1.02);
      box-shadow: 0 25px 45px rgba(78, 205, 196, 0.5);
    }
    
    .cv-card::before {
      content: '';
      position: absolute;
      top: -50%;
      left: -50%;
      width: 200%;
      height: 200%;
      background: radial-gradient(circle, rgba(255,255,255,0.3) 0%, rgba(255,255,255,0) 70%);
      opacity: 0;
      transition: opacity 0.6s;
      pointer-events: none;
    }
    
    .cv-card:hover::before {
      opacity: 1;
      animation: shine 1.5s;
    }
    
    @keyframes shine {
      0% { transform: translate(-30%, -30%) rotate(0deg); }
      100% { transform: translate(30%, 30%) rotate(180deg); }
    }
    
    .btn-contact {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 14px;
    }
    
    .btn-contact:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(34,197,94,0.4);
    }
    
    .btn-comment {
      background: linear-gradient(135deg, #ff6b6b, #f5576c);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 14px;
    }
    
    .btn-comment:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(255,107,107,0.4);
    }
    
    .action-buttons {
      display: flex;
      justify-content: center;
      gap: 15px;
      margin-top: 20px;
      margin-bottom: 20px;
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
    }
    
    .status-working {
      background: #22c55e;
      color: white;
    }
    
    .status-free {
      background: #ef4444;
      color: white;
    }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
      transition: all 0.2s;
      border: 1px solid rgba(34,197,94,0.4);
    }
    
    .skill-tag:hover {
      background: rgba(34,197,94,0.35);
      transform: scale(1.05);
    }
    
    .btn-danger {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-danger:hover {
      transform: scale(1.02);
      filter: brightness(1.1);
    }
    
    .profile-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 170px;
      height: 170px;
      background: radial-gradient(circle, rgba(34,197,94,0.3) 0%, rgba(34,197,94,0) 70%);
      border-radius: 50%;
      z-index: -1;
      animation: borderPulse 2s ease-in-out infinite;
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(16px);
      border-radius: 28px;
      border: 1px solid rgba(255, 255, 255, 0.25);
      box-shadow: 0 20px 40px rgba(0, 0, 0, 0.2);
    }
    
    .hero-overlay {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.05) 30%, rgba(0,0,0,0) 50%, rgba(26,26,58,0.6) 100%);
    }
    
    .hero-image {
      position: absolute;
      top: 0;
      width: 100%;
      height: 100%;
      background-size: cover;
      background-position: center 40%;
      filter: brightness(0.85) contrast(1.05);
      transition: transform 0.5s ease;
    }
    
    .hero-image:hover {
      transform: scale(1.01);
    }
    
    @media (max-width: 768px) {
      .order-list-container {
        width: 95% !important;
        margin: 15px auto !important;
      }
      .cards-container {
        flex-direction: column;
      }
      .gradient-border-box {
        width: 120px;
        height: 120px;
        margin-top: -50px;
        margin-left: 0;
      }
      .order-detail-buttons {
        flex-direction: column;
        gap: 10px;
      }
      .order-actions {
        flex-wrap: wrap;
        justify-content: flex-end;
      }
      .action-buttons {
        flex-direction: column;
        gap: 10px;
        align-items: center;
      }
      .cards-container::after {
        width: 90%;
        left: 5%;
        bottom: -10px;
      }
      .cv-card {
        min-width: 250px;
        padding: 30px 20px;
      }
      .modal-content, .modal-content-order {
        padding: 20px;
        width: 95%;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      
      <AdminNavbar 
        employeeInfo={workerInfo}
        onUpdateProfile={updateProfile}
        onLogout={() => {
          window.location.href = "/";
        }}
      />
      
      <div className="profile-hero-section">
        <div className="shooting-stars">
          {[...Array(60)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 3 + 1}px`,
              height: `${Math.random() * 3 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${Math.random() * 3 + 2}s`
            }} />
          ))}
          {[...Array(10)].map((_, i) => (
            <div key={`shooting-${i}`} className="shooting-star" style={{
              left: `${Math.random() * 80 + 10}%`,
              top: `${Math.random() * 40}%`,
              width: `${Math.random() * 60 + 40}px`,
              height: '2px',
              animationDelay: `${Math.random() * 8}s`,
              animationDuration: `${Math.random() * 2 + 1.5}s`,
              transform: `rotate(${Math.random() * 60 + 30}deg)`,
              background: `linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(255,255,150,0.8) 30%, rgba(255,255,255,0) 100%)`
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px", position: 'relative', overflow: 'hidden' }}>
            <div className="hero-image" style={{ 
              backgroundImage: `url(${workerInfo.coverImage})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center 40%'
            }}></div>
            <div className="hero-overlay"></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="profile-image-wrapper">
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt={workerInfo.name} src={workerInfo.profileImage} className="content" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }} />
                        </div>
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-3 lg:text-right lg:self-center"></div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-1"></div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-white">
                      {workerInfo.name}
                      <span className={`status-badge ${workerStatus === 'working' ? 'status-working' : 'status-free'}`}>
                        {workerStatus === 'working' ? '✅ En poste' : '📢 En recherche'}
                      </span>
                    </h3>
                    {workerStatus === 'working' && currentWorkPlace && (
                      <p className="text-md text-green-400 font-semibold mt-2">📍 Travaille chez : {currentWorkPlace}</p>
                    )}
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {workerInfo.location}
                    </div>
                    <div className="mb-2 text-gray-300 mt-10">
                      <i className="fas fa-briefcase mr-2 text-green-400"></i> {workerInfo.role}
                    </div>
                  </div>
                  
                  <div className="action-buttons">
                    <button className="btn-contact" onClick={() => alert(`📧 Email: ${workerInfo.email}\n📱 Téléphone: ${workerInfo.phone}`)}>
                      📧 Contacter
                    </button>
                    <button className="btn-comment" onClick={() => setShowCommentsList(true)}>
                      💬 Commenter
                    </button>
                  </div>
                  
                  <OrderList 
                    orders={orders} 
                    onUpdateOrderStatus={updateOrderStatus} 
                    onModalOpenChange={setIsAnyModalOpen}
                    targetOrderId={targetOrderId}
                    setTargetOrderId={setTargetOrderId}
                  />
                  
                  <TablesList 
                    completedOrders={completedOrders} 
                    onTableClick={(tableId) => setSelectedTableId(tableId)} 
                    onReturnToPendingOrders={returnToPendingOrders} 
                  />
                  
                  <div className="cards-container" style={{ transform: isAnyModalOpen || selectedTableId ? 'translateY(120px)' : 'translateY(0)', transition: 'transform 0.3s ease-in-out' }}>
                    
                    <div className="cv-card" onClick={() => setShowWorkerCV(true)}>
                      <div className="text-6xl mb-4">📄</div>
                      <h3 className="text-xl font-bold text-white mb-2" style={{ textShadow: '2px 2px 4px rgba(0,0,0,0.2)' }}>Mon CV</h3>
                      <p className="text-white/90 text-sm">Découvrez mon parcours professionnel</p>
                    </div>
                    
                    <div className="cv-card" onClick={() => setShowManagerCV(true)}>
                      <div className="text-6xl mb-4">⭐</div>
                      <h3 className="text-xl font-bold text-white mb-2" style={{ textShadow: '2px 2px 4px rgba(0,0,0,0.2)' }}>Évaluations</h3>
                      <p className="text-white/90 text-sm">Historique et retours des managers</p>
                    </div>
                    
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{workerInfo.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {workerInfo.skills.map((skill, i) => (
                            <span key={i} className="skill-tag">{skill}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {selectedTableId && selectedTable && (
        <TableDetailModal 
          table={selectedTable} 
          onLiberateTable={(tableId) => { liberateTable(tableId); setSelectedTableId(null); }}
          onClose={() => setSelectedTableId(null)}
          onReturnToPendingOrders={returnToPendingOrders}
        />
      )}
      
      {/* Modal CV */}
      {showWorkerCV && (
        <div className="modal-overlay" onClick={() => setShowWorkerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowWorkerCV(false)} className="close-btn">✕</button>
            <CVSection 
              workerInfo={workerInfo}
              isEditable={true}
              onSave={updateProfile}
            />
          </div>
        </div>
      )}
      
      {/* Modal Évaluations */}
      {showManagerCV && (
        <div className="modal-overlay" onClick={() => setShowManagerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '700px', width: '90%' }}>
            <button onClick={() => setShowManagerCV(false)} className="close-btn">✕</button>
            <EvaluationSection 
              workHistory={workHistory}
              onAddEvaluation={updateWorkHistory}
              canAddEvaluation={true}
              currentWorkPlace={currentWorkPlace}
              onStatusChange={changeWorkerStatus}
              workerStatus={workerStatus}
              availablePlaces={availablePlaces}
              onWorkPlaceChange={changeWorkPlace}
            />
          </div>
        </div>
      )}
      
      {/* Modal Commentaires */}
      {showCommentsList && (
        <div className="modal-overlay" onClick={() => setShowCommentsList(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowCommentsList(false)} className="close-btn">✕</button>
            <CommentSection 
              comments={comments}
              onAddComment={updateComments}
              canAddComment={true}
              targetName={workerInfo.name}
            />
          </div>
        </div>
      )}
      
      <SocialFooter socialLinks={socialLinks} />
      <Footer />
    </>
  );
}
